"#include <metal_stdlib>
using namespace metal;

struct PostProcessVertexOut {
    float4 position [[position]];
    float2 texCoord;
};

struct PostProcessUniforms {
    float2 resolution;
    float time;
    float _pad;
};

// Fullscreen triangle - no vertex buffer needed
vertex PostProcessVertexOut vertex_postprocess(uint vertexID [[vertex_id]]) {
    PostProcessVertexOut out;
    float2 pos = float2((vertexID << 1) & 2, vertexID & 2);
    out.position = float4(pos * 2.0 - 1.0, 0.0, 1.0);
    out.texCoord = float2(pos.x, 1.0 - pos.y);
    return out;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float radius = max(params[0], 1.0);
    float2 texelSize = 1.0 / uniforms.resolution;
    float4 result = float4(0.0);
    float weightSum = 0.0;
    float sigma = radius * 0.5;
    int r = int(radius);
    for (int i = -r; i <= r; i++) {
        float weight = exp(-0.5 * float(i * i) / (sigma * sigma));
        float2 offset = float2(float(i) * texelSize.x, 0.0);
        result += sceneTexture.sample(smp, in.texCoord + offset) * weight;
        weightSum += weight;
    }
    return result / weightSum;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float radius = max(params[0], 1.0);
    float2 texelSize = 1.0 / uniforms.resolution;
    float4 result = float4(0.0);
    float weightSum = 0.0;
    float sigma = radius * 0.5;
    int r = int(radius);
    for (int i = -r; i <= r; i++) {
        float weight = exp(-0.5 * float(i * i) / (sigma * sigma));
        float2 offset = float2(0.0, float(i) * texelSize.y);
        result += sceneTexture.sample(smp, in.texCoord + offset) * weight;
        weightSum += weight;
    }
    return result / weightSum;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float intensity = params[0];
    float threshold = params[1];
    float2 texelSize = 1.0 / uniforms.resolution;

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float4 bloom = float4(0.0);
    float weightSum = 0.0;

    // 9-tap blur of bright pixels
    for (int x = -4; x <= 4; x++) {
        for (int y = -4; y <= 4; y++) {
            float2 offset = float2(float(x), float(y)) * texelSize * 2.0;
            float4 s = sceneTexture.sample(smp, in.texCoord + offset);
            float brightness = dot(s.rgb, float3(0.2126, 0.7152, 0.0722));
            if (brightness > threshold) {
                float weight = exp(-0.5 * float(x*x + y*y) / 8.0);
                bloom += s * weight;
                weightSum += weight;
            }
        }
    }
    if (weightSum > 0.0) bloom /= weightSum;
    return color + bloom * intensity;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float amount = params[0] / uniforms.resolution.x;
    float2 dir = in.texCoord - 0.5;

    float r = sceneTexture.sample(smp, in.texCoord + dir * amount).r;
    float g = sceneTexture.sample(smp, in.texCoord).g;
    float b = sceneTexture.sample(smp, in.texCoord - dir * amount).b;
    float a = sceneTexture.sample(smp, in.texCoord).a;

    return float4(r, g, b, a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float strength = params[0];
    float radius = params[1];

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float2 uv = in.texCoord - 0.5;
    float dist = length(uv);
    float vig = smoothstep(radius, radius - 0.45, dist);
    color.rgb *= mix(1.0 - strength, 1.0, vig);
    return color;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float intensity = params[0];
    float4 color = sceneTexture.sample(smp, in.texCoord);

    float2 seed = in.texCoord * uniforms.resolution + uniforms.time * 1000.0;
    float noise = fract(sin(dot(seed, float2(12.9898, 78.233))) * 43758.5453);
    noise = (noise - 0.5) * intensity;

    color.rgb += noise;
    return color;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float lineIntensity = params[0];
    float curvature = params[1];

    // Barrel distortion
    float2 uv = in.texCoord - 0.5;
    float dist = dot(uv, uv);
    uv *= 1.0 + dist * curvature * 0.01;
    uv += 0.5;

    if (uv.x < 0.0 || uv.x > 1.0 || uv.y < 0.0 || uv.y > 1.0)
        return float4(0.0);

    float4 color = sceneTexture.sample(smp, uv);

    // Scanlines
    float scanline = sin(uv.y * uniforms.resolution.y * 3.14159) * 0.5 + 0.5;
    color.rgb *= 1.0 - lineIntensity * (1.0 - scanline);

    // Slight RGB offset for CRT feel
    float offset = 0.001;
    color.r = sceneTexture.sample(smp, uv + float2(offset, 0)).r;
    color.b = sceneTexture.sample(smp, uv - float2(offset, 0)).b;

    return color;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float k = params[0];
    float2 uv = in.texCoord - 0.5;
    float r2 = dot(uv, uv);
    uv *= 1.0 + k * r2;
    uv += 0.5;

    if (uv.x < 0.0 || uv.x > 1.0 || uv.y < 0.0 || uv.y > 1.0)
        return float4(0.0);

    return sceneTexture.sample(smp, uv);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float strength = params[0];
    float2 texelSize = 1.0 / uniforms.resolution;

    // Sobel kernels
    float tl = dot(sceneTexture.sample(smp, in.texCoord + float2(-1, -1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float t  = dot(sceneTexture.sample(smp, in.texCoord + float2( 0, -1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float tr = dot(sceneTexture.sample(smp, in.texCoord + float2( 1, -1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float l  = dot(sceneTexture.sample(smp, in.texCoord + float2(-1,  0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float r  = dot(sceneTexture.sample(smp, in.texCoord + float2( 1,  0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float bl = dot(sceneTexture.sample(smp, in.texCoord + float2(-1,  1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float b  = dot(sceneTexture.sample(smp, in.texCoord + float2( 0,  1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float br = dot(sceneTexture.sample(smp, in.texCoord + float2( 1,  1) * texelSize).rgb, float3(0.299, 0.587, 0.114));

    float gx = -tl - 2.0*l - bl + tr + 2.0*r + br;
    float gy = -tl - 2.0*t - tr + bl + 2.0*b + br;
    float edge = sqrt(gx*gx + gy*gy) * strength;

    return float4(float3(edge), 1.0);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float pixelSize = max(params[0], 1.0);
    float2 size = pixelSize / uniforms.resolution;
    float2 uv = floor(in.texCoord / size) * size + size * 0.5;
    return sceneTexture.sample(smp, uv);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float strength = params[0];
    float2 texelSize = 1.0 / uniforms.resolution;

    float4 center = sceneTexture.sample(smp, in.texCoord);
    float4 blur = sceneTexture.sample(smp, in.texCoord + float2(-1, 0) * texelSize)
                + sceneTexture.sample(smp, in.texCoord + float2( 1, 0) * texelSize)
                + sceneTexture.sample(smp, in.texCoord + float2( 0,-1) * texelSize)
                + sceneTexture.sample(smp, in.texCoord + float2( 0, 1) * texelSize);
    blur *= 0.25;

    return center + (center - blur) * strength;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float exposure = params[0];
    float4 color = sceneTexture.sample(smp, in.texCoord);
    float3 c = color.rgb * exposure;

    // ACES approximation (Narkowicz 2015)
    float3 mapped = (c * (2.51 * c + 0.03)) / (c * (2.43 * c + 0.59) + 0.14);
    return float4(saturate(mapped), color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float angle = params[0];
    float strength = params[1];
    float2 dir = float2(cos(angle), sin(angle)) * strength / uniforms.resolution;

    float4 result = float4(0.0);
    int samples = 9;
    for (int i = 0; i < samples; i++) {
        float t = float(i) / float(samples - 1) - 0.5;
        result += sceneTexture.sample(smp, in.texCoord + dir * t);
    }
    return result / float(samples);
}"

"// Hash function for noise generation
float hash21(float2 p) {
    p = fract(p * float2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
}

float2 hash22(float2 p) {
    float3 p3 = fract(float3(p.xyx) * float3(0.1031, 0.1030, 0.0973));
    p3 += dot(p3, p3.yzx + 33.33);
    return fract((p3.xx + p3.yz) * p3.zy);
}

// Value noise
float valueNoise(float2 p) {
    float2 i = floor(p);
    float2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f); // smoothstep

    float a = hash21(i);
    float b = hash21(i + float2(1, 0));
    float c = hash21(i + float2(0, 1));
    float d = hash21(i + float2(1, 1));

    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

// fBm (fractal Brownian motion)
float fbm(float2 p, int octaves) {
    float value = 0.0;
    float amplitude = 0.5;
    float frequency = 1.0;
    for (int i = 0; i < octaves; i++) {
        value += amplitude * valueNoise(p * frequency);
        frequency *= 2.0;
        amplitude *= 0.5;
    }
    return value;
}

// Voronoi distance
float voronoi(float2 p) {
    float2 i = floor(p);
    float2 f = fract(p);
    float minDist = 1.0;
    for (int y = -1; y <= 1; y++) {
        for (int x = -1; x <= 1; x++) {
            float2 neighbor = float2(float(x), float(y));
            float2 point = hash22(i + neighbor);
            float2 diff = neighbor + point - f;
            minDist = min(minDist, length(diff));
        }
    }
    return minDist;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float scale = params[0];
    int octaves = int(params[1]);
    float intensity = params[2];

    float4 scene = sceneTexture.sample(smp, in.texCoord);
    float2 uv = in.texCoord * scale;
    float n = fbm(uv + uniforms.time * 0.5, octaves) * intensity;

    return float4(scene.rgb * (0.5 + n * 0.5), scene.a);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float scale = params[0];
    float speed = params[1];

    float2 uv = in.texCoord * scale + uniforms.time * speed;
    float v = voronoi(uv);

    float4 scene = sceneTexture.sample(smp, in.texCoord);
    return float4(scene.rgb * (0.5 + v * 0.5), scene.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float density = params[0];
    float3 fogColor = float3(params[1], params[2], params[3]);

    float4 color = sceneTexture.sample(smp, in.texCoord);
    // Use luminance as fake depth
    float depth = 1.0 - dot(color.rgb, float3(0.299, 0.587, 0.114));
    float fogFactor = 1.0 - exp(-density * depth * depth);

    color.rgb = mix(color.rgb, fogColor, fogFactor);
    return color;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float2 lightPos = float2(params[0], params[1]);
    float intensity = params[2];
    float decay = params[3];

    float2 delta = (in.texCoord - lightPos) / 64.0;
    float2 uv = in.texCoord;
    float4 color = sceneTexture.sample(smp, in.texCoord);

    float illumination = 1.0;
    float4 rays = float4(0.0);
    for (int i = 0; i < 64; i++) {
        uv -= delta;
        float4 s = sceneTexture.sample(smp, uv);
        s *= illumination * 0.015;
        rays += s;
        illumination *= decay;
    }

    return color + rays * intensity;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float scale = params[0];
    float speed = params[1];
    float coverage = params[2];
    float opacity = params[3];

    float4 scene = sceneTexture.sample(smp, in.texCoord);
    float2 uv = in.texCoord * scale + float2(uniforms.time * speed, 0.0);

    float n = fbm(uv, 6);
    float cloud = smoothstep(coverage - 0.1, coverage + 0.1, n);

    scene.rgb = mix(scene.rgb, float3(1.0), cloud * opacity);
    return scene;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float strength = params[0];
    float speed = params[1];

    float2 uv = in.texCoord;
    float n1 = valueNoise(uv * 20.0 + float2(uniforms.time * speed, 0));
    float n2 = valueNoise(uv * 20.0 + float2(0, uniforms.time * speed * 0.7));

    float2 distortion = (float2(n1, n2) - 0.5) * strength / uniforms.resolution;
    return sceneTexture.sample(smp, uv + distortion);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float scale = params[0];
    float speed = params[1];
    float intensity = params[2];

    float4 scene = sceneTexture.sample(smp, in.texCoord);

    // Dual-layer animated Voronoi for caustic pattern
    float v1 = voronoi(in.texCoord * scale + uniforms.time * speed);
    float v2 = voronoi(in.texCoord * scale * 1.5 - uniforms.time * speed * 0.7);
    float caustic = pow(v1 * v2, 0.5) * intensity;

    scene.rgb += caustic;
    return scene;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float2 center = float2(params[0], params[1]);
    float frequency = params[2];
    float amplitude = params[3];
    float decayRate = params[4];

    float2 uv = in.texCoord;
    float2 delta = uv - center;
    float dist = length(delta);

    float wave = sin(dist * frequency - uniforms.time * 10.0) * exp(-dist * decayRate);
    float2 dir = (length(delta) > 0.001) ? normalize(delta) : float2(1.0, 0.0);
    float2 offset = dir * wave * amplitude / uniforms.resolution;

    return sceneTexture.sample(smp, uv + offset);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float3 lightPos = float3(params[0], params[1], params[2]);
    float ambient = params[3];

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float2 texelSize = 1.0 / uniforms.resolution;

    // Derive normal from luminance gradient
    float l = dot(sceneTexture.sample(smp, in.texCoord + float2(-1, 0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float r = dot(sceneTexture.sample(smp, in.texCoord + float2( 1, 0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float t = dot(sceneTexture.sample(smp, in.texCoord + float2( 0,-1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float b = dot(sceneTexture.sample(smp, in.texCoord + float2( 0, 1) * texelSize).rgb, float3(0.299, 0.587, 0.114));

    float3 normal = normalize(float3(l - r, t - b, 1.0));
    float3 fragPos = float3(in.texCoord * uniforms.resolution, 0.0);
    float3 lightDir = normalize(lightPos - fragPos);

    float diffuse = max(dot(normal, lightDir), 0.0);
    float lighting = ambient + (1.0 - ambient) * diffuse;

    color.rgb *= lighting;
    return color;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float rimWidth = params[0];
    float3 rimColor = float3(params[1], params[2], params[3]);
    float rimPower = params[4];

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float2 texelSize = rimWidth / uniforms.resolution;

    // Edge detection on alpha channel for rim
    float a = color.a;
    float aL = sceneTexture.sample(smp, in.texCoord + float2(-1, 0) * texelSize).a;
    float aR = sceneTexture.sample(smp, in.texCoord + float2( 1, 0) * texelSize).a;
    float aT = sceneTexture.sample(smp, in.texCoord + float2( 0,-1) * texelSize).a;
    float aB = sceneTexture.sample(smp, in.texCoord + float2( 0, 1) * texelSize).a;

    float edge = abs(a - aL) + abs(a - aR) + abs(a - aT) + abs(a - aB);
    float rim = pow(saturate(edge), 1.0 / rimPower);

    color.rgb += rimColor * rim;
    return color;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float dotSize = params[0];
    float angle = params[1] * 3.14159 / 180.0;

    float2 uv = in.texCoord * uniforms.resolution;

    // Rotate grid
    float ca = cos(angle), sa = sin(angle);
    float2 rotUV = float2(ca * uv.x + sa * uv.y, -sa * uv.x + ca * uv.y);
    float2 cell = fract(rotUV / dotSize) - 0.5;

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));

    // Dot radius proportional to luminance
    float radius = lum * 0.5;
    float dot = smoothstep(radius + 0.02, radius - 0.02, length(cell));

    return float4(float3(dot), color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float levels = max(params[0], 1.0);
    float4 color = sceneTexture.sample(smp, in.texCoord);
    color.rgb = floor(color.rgb * levels + 0.5) / levels;
    return color;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float intensity = params[0];
    float speed = params[1];

    float2 uv = in.texCoord;
    float t = floor(uniforms.time * speed);

    // Full-width horizontal scanline displacement — whole rows shift left/right
    float lineHash = hash21(float2(floor(uv.y * 80.0), t));
    float lineShift = 0.0;
    if (lineHash > 1.0 - intensity * 0.4) {
        lineShift = (hash21(float2(floor(uv.y * 80.0) * 3.7, t * 1.3)) - 0.5) * intensity * 0.3;
    }

    // Large block displacement — rectangular chunks jump
    float2 block = float2(floor(uv.x * 8.0), floor(uv.y * 12.0));
    float blockHash = hash21(block + t * 0.5);
    float2 blockShift = float2(0.0);
    if (blockHash > 1.0 - intensity * 0.15) {
        blockShift.x = (hash21(block * 2.0 + t) - 0.5) * intensity * 0.2;
        blockShift.y = (hash21(block * 3.0 + t) - 0.5) * intensity * 0.05;
    }

    float2 displaced = uv + float2(lineShift, 0.0) + blockShift;

    // RGB channel split — increases with line distortion
    float rgbSplit = intensity * 0.01 * (1.0 + lineHash * 2.0);
    float r = sceneTexture.sample(smp, displaced + float2(rgbSplit, 0.0)).r;
    float g = sceneTexture.sample(smp, displaced).g;
    float b = sceneTexture.sample(smp, displaced - float2(rgbSplit, 0.0)).b;
    float a = sceneTexture.sample(smp, uv).a;

    float4 color = float4(r, g, b, a);

    // Static noise bars — thin horizontal lines of pure noise
    float staticHash = hash21(float2(floor(uv.y * uniforms.resolution.y), uniforms.time * 100.0));
    if (staticHash > 1.0 - intensity * 0.05) {
        float noise = hash21(uv * uniforms.resolution + uniforms.time * 1000.0);
        color.rgb = mix(color.rgb, float3(noise), 0.8);
    }

    return color;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float progress = params[0];
    float edgeWidth = params[1];
    float3 edgeColor = float3(params[2], params[3], params[4]);

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float n = valueNoise(in.texCoord * 20.0);

    if (n < progress) discard_fragment();

    float edge = smoothstep(progress, progress + edgeWidth, n);
    color.rgb = mix(edgeColor, color.rgb, edge);
    return color;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float dotSize = max(params[0], 1.0);
    float paper = params[1];

    float4 color = sceneTexture.sample(smp, in.texCoord);

    // RGB to CMYK
    float k = 1.0 - max(max(color.r, color.g), color.b);
    float invK = (k < 1.0) ? 1.0 / (1.0 - k) : 0.0;
    float c = (1.0 - color.r - k) * invK;
    float m = (1.0 - color.g - k) * invK;
    float y = (1.0 - color.b - k) * invK;

    float2 uv = in.texCoord * uniforms.resolution;

    // Each channel gets a different screen angle (classic print angles)
    constant float angles[4] = { 15.0, 75.0, 0.0, 45.0 }; // C, M, Y, K
    float channels[4] = { c, m, y, k };
    float3 cmykColors[4] = {
        float3(0.0, 1.0, 1.0), float3(1.0, 0.0, 1.0),
        float3(1.0, 1.0, 0.0), float3(0.0, 0.0, 0.0)
    };

    float3 result = float3(paper);
    for (int i = 0; i < 4; i++) {
        float a = angles[i] * 3.14159 / 180.0;
        float ca = cos(a), sa = sin(a);
        float2 rotUV = float2(ca * uv.x + sa * uv.y, -sa * uv.x + ca * uv.y);
        float2 cell = fract(rotUV / dotSize) - 0.5;
        float radius = channels[i] * 0.5;
        float d = smoothstep(radius + 0.03, radius - 0.03, length(cell));
        // Subtractive color mixing
        result -= (float3(1.0) - cmykColors[i]) * d * channels[i];
    }

    return float4(saturate(result), color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float spacing = max(params[0], 1.0);
    float angle = params[1] * 3.14159 / 180.0;
    float sharpness = params[2];

    float2 uv = in.texCoord * uniforms.resolution;
    float ca = cos(angle), sa = sin(angle);
    float projected = ca * uv.x + sa * uv.y;
    float cell = fract(projected / spacing) - 0.5;

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));

    // Line width varies with luminance — dark areas get thicker lines
    float lineWidth = (1.0 - lum) * 0.5;
    float line = smoothstep(lineWidth + 0.02 * sharpness, lineWidth - 0.02 * sharpness, abs(cell));

    return float4(float3(1.0 - line), color.a);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float spacing = max(params[0], 1.0);
    float weight = params[1];

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));
    float2 uv = in.texCoord * uniforms.resolution;

    // Paper color (warm white)
    float3 result = float3(0.95, 0.93, 0.88);

    // Four hatch layers at different angles, activated by darkness level
    constant float hatchAngles[4] = { 0.785, -0.785, 0.0, 1.5708 }; // 45, -45, 0, 90 degrees
    float thresholds[4] = { 0.8, 0.6, 0.4, 0.2 };

    float ink = 0.0;
    for (int i = 0; i < 4; i++) {
        if (lum < thresholds[i]) {
            float a = hatchAngles[i];
            float ca = cos(a), sa = sin(a);
            float projected = ca * uv.x + sa * uv.y;

            // Add slight hand-drawn wobble
            float wobble = valueNoise(float2(projected * 0.1, float(i))) * 1.5;
            projected += wobble;

            float cell = fract(projected / spacing) - 0.5;
            float lineW = weight * 0.12 * (1.0 - lum / thresholds[i]);
            ink += smoothstep(lineW + 0.02, lineW - 0.02, abs(cell)) * 0.35;
        }
    }

    result -= ink;
    return float4(saturate(result), color.a);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float density = params[0];
    float dotSize = max(params[1], 0.5);

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));

    float2 pixel = in.texCoord * uniforms.resolution;
    float2 cell = floor(pixel / dotSize);

    // Jittered dot center within each cell
    float2 jitter = hash22(cell) * 0.8 + 0.1; // Keep dots away from cell edges
    float2 dotCenter = (cell + jitter) * dotSize;
    float dist = length(pixel - dotCenter);

    // Probability of dot appearing scales with darkness
    float threshold = lum * density;
    float cellHash = hash21(cell * 13.7);

    // Draw dot if random value exceeds luminance-based threshold
    float dotRadius = dotSize * 0.35 * (1.0 - lum * 0.5);
    float dot = smoothstep(dotRadius + 0.5, dotRadius - 0.5, dist);
    float visible = step(threshold, cellHash);

    // Warm paper background, dark ink dots
    float3 paper = float3(0.95, 0.92, 0.87);
    float3 inkColor = float3(0.08, 0.06, 0.04);
    return float4(mix(paper, inkColor, dot * (1.0 - visible)), color.a);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float edgeStrength = params[0];
    float shadeDensity = params[1];

    float2 texelSize = 1.0 / uniforms.resolution;
    float2 uv = in.texCoord;

    // Sobel edge detection
    float tl = dot(sceneTexture.sample(smp, uv + float2(-1,-1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float t  = dot(sceneTexture.sample(smp, uv + float2( 0,-1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float tr = dot(sceneTexture.sample(smp, uv + float2( 1,-1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float l  = dot(sceneTexture.sample(smp, uv + float2(-1, 0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float r  = dot(sceneTexture.sample(smp, uv + float2( 1, 0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float bl = dot(sceneTexture.sample(smp, uv + float2(-1, 1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float b  = dot(sceneTexture.sample(smp, uv + float2( 0, 1) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float br = dot(sceneTexture.sample(smp, uv + float2( 1, 1) * texelSize).rgb, float3(0.299, 0.587, 0.114));

    float gx = -tl - 2.0*l - bl + tr + 2.0*r + br;
    float gy = -tl - 2.0*t - tr + bl + 2.0*b + br;
    float edge = saturate(sqrt(gx*gx + gy*gy) * edgeStrength);

    // Pencil shading strokes (diagonal hatching based on luminance)
    float4 color = sceneTexture.sample(smp, uv);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));
    float2 pixel = uv * uniforms.resolution;

    float hatch1 = abs(fract((pixel.x + pixel.y) / 6.0) - 0.5) * 2.0;
    float hatch2 = abs(fract((pixel.x - pixel.y) / 4.0) - 0.5) * 2.0;

    float shade = 1.0;
    if (lum < 0.75) shade -= smoothstep(0.5, 0.3, hatch1) * 0.3 * shadeDensity;
    if (lum < 0.50) shade -= smoothstep(0.5, 0.3, hatch2) * 0.3 * shadeDensity;
    if (lum < 0.25) shade -= 0.2 * shadeDensity;

    // Paper texture
    float paper = 0.95 + valueNoise(pixel * 0.5) * 0.05;

    float pencil = paper * shade * (1.0 - edge);
    return float4(float3(pencil), color.a);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float scale = params[0];
    float outlineWidth = params[1];
    float satBoost = params[2];

    float2 uv = in.texCoord;
    float2 p = uv * scale;
    float2 ip = floor(p);
    float2 fp = fract(p);

    // Find nearest two Voronoi centers for edge detection
    float minDist = 10.0;
    float secondDist = 10.0;
    float2 nearestCell = float2(0.0);

    for (int y = -1; y <= 1; y++) {
        for (int x = -1; x <= 1; x++) {
            float2 neighbor = float2(float(x), float(y));
            float2 point = hash22(ip + neighbor);
            float2 diff = neighbor + point - fp;
            float d = length(diff);
            if (d < minDist) {
                secondDist = minDist;
                minDist = d;
                nearestCell = ip + neighbor;
            } else if (d < secondDist) {
                secondDist = d;
            }
        }
    }

    // Sample color from cell center
    float2 cellCenter = (nearestCell + hash22(nearestCell)) / scale;
    float4 color = sceneTexture.sample(smp, cellCenter);

    // Boost saturation for stained glass effect
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));
    color.rgb = mix(float3(lum), color.rgb, satBoost);

    // Dark lead outlines between cells
    float edgeDist = secondDist - minDist;
    float outline = smoothstep(0.0, outlineWidth, edgeDist);

    // Simulate light passing through — brighten centers
    float glow = 1.0 + (1.0 - minDist) * 0.3;
    color.rgb *= outline * glow;

    // Dark lead color
    color.rgb = mix(float3(0.05, 0.04, 0.03), color.rgb, outline);
    return float4(color.rgb, color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float2 center = float2(params[0], params[1]);
    float radius = params[2];
    float zoom = params[3];
    float edgeDist_param = params[4];

    float2 uv = in.texCoord;
    float2 delta = uv - center;

    // Correct for aspect ratio
    float aspect = uniforms.resolution.x / uniforms.resolution.y;
    float2 scaledDelta = delta * float2(aspect, 1.0);
    float dist = length(scaledDelta);

    if (dist > radius) {
        // Outside lens — slight darkening to simulate glass edge shadow
        float shadow = smoothstep(radius, radius + 0.01, dist);
        return sceneTexture.sample(smp, uv) * mix(0.85, 1.0, shadow);
    }

    // Inside lens — zoom from center with barrel distortion at edge
    float normalizedDist = dist / radius;
    float distortion = 1.0 + normalizedDist * normalizedDist * edgeDist_param;
    float2 zoomedUV = center + delta / zoom * distortion;

    float4 color = sceneTexture.sample(smp, zoomedUV);

    // Lens highlight
    float2 highlightPos = center + float2(-0.03, -0.04);
    float2 hDelta = (uv - highlightPos) * float2(aspect, 1.0);
    float highlight = exp(-dot(hDelta, hDelta) * 800.0) * 0.4;
    color.rgb += highlight;

    // Lens rim
    float rim = smoothstep(radius - 0.005, radius, dist);
    color.rgb = mix(color.rgb, float3(0.2), rim);

    return color;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float contrast = params[0];
    float grainScale = params[1];
    float angle = params[2] * 3.14159 / 180.0;

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));

    // High contrast threshold
    lum = saturate((lum - 0.5) * contrast + 0.5);

    // Directional wood grain
    float2 uv = in.texCoord * uniforms.resolution;
    float ca = cos(angle), sa = sin(angle);
    float projected = ca * uv.x + sa * uv.y;
    float cross_dir = -sa * uv.x + ca * uv.y;

    // Elongated noise along grain direction
    float grain = fbm(float2(projected / grainScale, cross_dir / (grainScale * 0.15)), 4);
    grain = grain * 0.4 + 0.8;

    // Combine — dark ink on light paper
    float threshold = lum * grain;
    float ink = smoothstep(0.45, 0.55, threshold);

    // Ink color (very dark brown) and paper (cream)
    float3 inkColor = float3(0.05, 0.03, 0.02);
    float3 paperColor = float3(0.92, 0.88, 0.78);
    return float4(mix(inkColor, paperColor, ink), color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float levels = max(params[0], 2.0);
    float dotSize = max(params[1], 1.0);
    float satBoost = params[2];

    float4 color = sceneTexture.sample(smp, in.texCoord);

    // Boost saturation
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));
    color.rgb = saturate(mix(float3(lum), color.rgb, satBoost));

    // Posterize
    color.rgb = floor(color.rgb * levels + 0.5) / levels;

    // Ben-Day dots on shadows
    float2 uv = in.texCoord * uniforms.resolution;
    float2 cell = fract(uv / dotSize) - 0.5;
    float dotDist = length(cell);

    // Dots appear in darker areas
    float darkness = 1.0 - lum;
    float dotRadius = darkness * 0.45;
    float dots = smoothstep(dotRadius + 0.03, dotRadius - 0.03, dotDist);

    // Bold black outline via edge detection
    float2 texelSize = 1.0 / uniforms.resolution;
    float cl = dot(sceneTexture.sample(smp, in.texCoord + float2(-2, 0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float cr = dot(sceneTexture.sample(smp, in.texCoord + float2( 2, 0) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float ct = dot(sceneTexture.sample(smp, in.texCoord + float2( 0,-2) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float cb = dot(sceneTexture.sample(smp, in.texCoord + float2( 0, 2) * texelSize).rgb, float3(0.299, 0.587, 0.114));
    float edge = saturate(length(float2(cr - cl, cb - ct)) * 3.0);

    // Composite: color with dots, then outline
    float3 result = mix(color.rgb, color.rgb * 0.4, dots * 0.5);
    result = mix(result, float3(0.0), edge);
    return float4(result, color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float cellSize = max(params[0], 1.0);
    float angle = params[1] * 3.14159 / 180.0;

    float2 uv = in.texCoord * uniforms.resolution;
    float ca = cos(angle), sa = sin(angle);
    float2 rotUV = float2(ca * uv.x + sa * uv.y, -sa * uv.x + ca * uv.y);
    float2 cell = fract(rotUV / cellSize) - 0.5;

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));

    // Diamond distance (L1 / Manhattan)
    float diamondDist = abs(cell.x) + abs(cell.y);
    float radius = lum * 0.5;
    float diamond = smoothstep(radius + 0.03, radius - 0.03, diamondDist);

    return float4(float3(diamond), color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float segments = max(params[0], 1.0);
    float rotation = params[1];

    float2 uv = in.texCoord - 0.5;
    float angle = atan2(uv.y, uv.x) + rotation;
    float radius = length(uv);

    // Mirror into segments
    float segAngle = 3.14159265 * 2.0 / segments;
    angle = abs(fmod(angle, segAngle) - segAngle * 0.5);

    float2 mirroredUV = float2(cos(angle), sin(angle)) * radius + 0.5;
    return sceneTexture.sample(smp, mirroredUV);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float amplitude = params[0];
    float frequency = params[1];
    float speed = params[2];
    float angle = params[3];

    float2 uv = in.texCoord;
    float2 dir = float2(cos(angle), sin(angle));
    float2 perp = float2(-dir.y, dir.x);
    float projection = dot(uv * uniforms.resolution, dir);
    float displacement = sin(projection / uniforms.resolution.x * frequency * 6.28318 - uniforms.time * speed) * amplitude;
    uv += perp * displacement / uniforms.resolution;
    return sceneTexture.sample(smp, uv);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float2 center = float2(params[0], params[1]);
    float strength = params[2];
    int sampleCount = max(int(params[3]), 1);

    float2 dir = in.texCoord - center;
    float4 result = float4(0.0);
    for (int i = 0; i < sampleCount; i++) {
        float t = float(i) / float(sampleCount);
        result += sceneTexture.sample(smp, in.texCoord - dir * t * strength);
    }
    return result / float(sampleCount);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float focusY = params[0];
    float bandWidth = params[1];
    float maxRadius = params[2];

    float dist = abs(in.texCoord.y - focusY);
    float blur = smoothstep(0.0, bandWidth, dist) * maxRadius;

    if (blur < 0.5) return sceneTexture.sample(smp, in.texCoord);

    float2 texelSize = 1.0 / uniforms.resolution;
    float4 result = float4(0.0);
    float weightSum = 0.0;
    float sigma = blur * 0.5;
    int r = int(blur);
    for (int x = -r; x <= r; x++) {
        for (int y = -r; y <= r; y++) {
            float weight = exp(-0.5 * float(x*x + y*y) / (sigma * sigma));
            result += sceneTexture.sample(smp, in.texCoord + float2(float(x), float(y)) * texelSize) * weight;
            weightSum += weight;
        }
    }
    return result / weightSum;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float contrast = params[0];
    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));
    lum = saturate((lum - 0.5) * contrast + 0.5);

    // 5-stop heat ramp: black → blue → cyan → green → yellow → red → white
    float3 heat;
    if (lum < 0.15)      heat = mix(float3(0.0), float3(0.0, 0.0, 0.5), lum / 0.15);
    else if (lum < 0.33) heat = mix(float3(0.0, 0.0, 0.5), float3(0.0, 1.0, 1.0), (lum - 0.15) / 0.18);
    else if (lum < 0.5)  heat = mix(float3(0.0, 1.0, 1.0), float3(0.0, 1.0, 0.0), (lum - 0.33) / 0.17);
    else if (lum < 0.67) heat = mix(float3(0.0, 1.0, 0.0), float3(1.0, 1.0, 0.0), (lum - 0.5) / 0.17);
    else if (lum < 0.85) heat = mix(float3(1.0, 1.0, 0.0), float3(1.0, 0.0, 0.0), (lum - 0.67) / 0.18);
    else                 heat = mix(float3(1.0, 0.0, 0.0), float3(1.0, 1.0, 1.0), (lum - 0.85) / 0.15);

    return float4(heat, color.a);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float brightness = params[0];
    float noiseIntensity = params[1];

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114)) * brightness;

    // Animated grain
    float noise = hash21(in.texCoord * uniforms.resolution + uniforms.time * 800.0);
    lum += (noise - 0.5) * noiseIntensity;

    // Scanlines
    float scanline = sin(in.texCoord.y * uniforms.resolution.y * 3.14159) * 0.5 + 0.5;
    lum *= 0.85 + 0.15 * scanline;

    // Vignette
    float2 vig = in.texCoord - 0.5;
    lum *= 1.0 - dot(vig, vig) * 1.5;

    // Phosphor green tint
    float3 green = float3(0.1, 1.0, 0.2) * saturate(lum);
    return float4(green, color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float3 shadowColor = float3(params[0], params[1], params[2]);
    float3 highlightColor = float3(params[3], params[4], params[5]);

    float4 color = sceneTexture.sample(smp, in.texCoord);
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));
    return float4(mix(shadowColor, highlightColor, lum), color.a);
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float scratchIntensity = params[0];
    float flicker = params[1];
    float grain = params[2];

    float4 color = sceneTexture.sample(smp, in.texCoord);

    // Sepia tone
    float lum = dot(color.rgb, float3(0.299, 0.587, 0.114));
    float3 sepia = float3(lum * 1.2, lum * 1.0, lum * 0.7);

    // Random brightness flicker
    float flickerVal = 1.0 + (hash21(float2(floor(uniforms.time * 12.0), 0.0)) - 0.5) * flicker;
    sepia *= flickerVal;

    // Vertical scratch lines
    float scratchX = hash21(float2(floor(uniforms.time * 7.0), 0.0));
    float scratch = 1.0 - smoothstep(0.0, 0.002, abs(in.texCoord.x - scratchX)) * scratchIntensity;
    sepia += scratch * 0.3 * step(0.7, hash21(float2(floor(uniforms.time * 14.0), 1.0)));

    // Film grain
    float noise = hash21(in.texCoord * uniforms.resolution + uniforms.time * 500.0);
    sepia += (noise - 0.5) * grain;

    // Vignette
    float2 vig = in.texCoord - 0.5;
    sepia *= 1.0 - dot(vig, vig) * 1.8;

    return float4(saturate(sepia), color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float levels = max(params[0], 2.0);
    float strength = params[1];

    // 4x4 Bayer matrix
    constant float bayer[16] = {
         0.0/16.0,  8.0/16.0,  2.0/16.0, 10.0/16.0,
        12.0/16.0,  4.0/16.0, 14.0/16.0,  6.0/16.0,
         3.0/16.0, 11.0/16.0,  1.0/16.0,  9.0/16.0,
        15.0/16.0,  7.0/16.0, 13.0/16.0,  5.0/16.0
    };

    float2 pixel = in.texCoord * uniforms.resolution;
    int idx = (int(pixel.x) % 4) + (int(pixel.y) % 4) * 4;
    float threshold = bayer[idx] - 0.5;

    float4 color = sceneTexture.sample(smp, in.texCoord);
    color.rgb += threshold * strength / levels;
    color.rgb = floor(color.rgb * levels + 0.5) / levels;
    return color;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float intensity = params[0];
    float speed = params[1];
    float wind = params[2];

    float4 scene = sceneTexture.sample(smp, in.texCoord);

    float rainAccum = 0.0;
    // Three depth layers (near, mid, far)
    for (int layer = 0; layer < 3; layer++) {
        float scale = 40.0 + float(layer) * 30.0;
        float layerSpeed = speed * (1.5 - float(layer) * 0.3);
        float layerAlpha = 0.4 - float(layer) * 0.1;

        // Sheared UV for wind angle
        float2 uv = in.texCoord * float2(scale, scale * 0.3);
        uv.x += uv.y * wind;
        uv.y += uniforms.time * layerSpeed + float(layer) * 17.3;

        // Thin vertical streaks
        float cellX = floor(uv.x);
        float fracX = fract(uv.x);
        float dropHash = hash21(float2(cellX, float(layer) + 7.0));
        float dropY = fract(uv.y + dropHash * 100.0);

        // Streak shape: thin horizontally, elongated vertically
        float streak = smoothstep(0.45, 0.5, fracX) * smoothstep(0.55, 0.5, fracX);
        streak *= smoothstep(0.0, 0.1, dropY) * smoothstep(0.5, 0.1, dropY);
        streak *= step(0.6, dropHash); // Only some cells have rain

        rainAccum += streak * layerAlpha;
    }

    scene.rgb += rainAccum * intensity;
    return scene;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float tintStrength = params[0];
    float wobble = params[1];
    float causticIntensity = params[2];

    // Wobble distortion
    float2 uv = in.texCoord;
    uv.x += sin(uv.y * 15.0 + uniforms.time * 1.5) * wobble / uniforms.resolution.x;
    uv.y += cos(uv.x * 12.0 + uniforms.time * 1.2) * wobble / uniforms.resolution.y;

    float4 color = sceneTexture.sample(smp, uv);

    // Teal water tint
    float3 waterColor = float3(0.1, 0.5, 0.6);
    color.rgb = mix(color.rgb, color.rgb * waterColor + waterColor * 0.1, tintStrength);

    // Light caustics from above
    float v1 = voronoi(in.texCoord * 12.0 + float2(uniforms.time * 0.5, uniforms.time * 0.3));
    float v2 = voronoi(in.texCoord * 16.0 - float2(uniforms.time * 0.4, uniforms.time * 0.6));
    float caustic = pow(v1 * v2, 0.4);

    // Light shafts fade with depth (stronger at top)
    float depthFade = 1.0 - in.texCoord.y;
    color.rgb += caustic * causticIntensity * depthFade;

    // Depth fog (darker at bottom)
    color.rgb *= 0.7 + 0.3 * depthFade;

    return color;
}"

"
fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float intensity = params[0];
    float speed = params[1];
    float scale = params[2];

    float4 scene = sceneTexture.sample(smp, in.texCoord);

    // Aurora only in upper portion of screen
    float verticalFade = smoothstep(0.8, 0.15, in.texCoord.y);
    if (verticalFade < 0.01) return scene;

    float2 uv = float2(in.texCoord.x * scale, in.texCoord.y * 0.5);

    // Layered noise for flowing curtain shape
    float n1 = fbm(float2(uv.x * 2.0 + uniforms.time * speed * 0.3, uv.y + uniforms.time * speed * 0.1), 4);
    float n2 = fbm(float2(uv.x * 3.0 - uniforms.time * speed * 0.2, uv.y * 1.5), 3);
    float curtain = smoothstep(0.3, 0.7, n1) * smoothstep(0.2, 0.6, n2);

    // Color gradient — green center, purple/blue edges
    float colorPhase = n1 * 2.0 + in.texCoord.x * 1.5;
    float3 auroraColor;
    float cp = fract(colorPhase);
    if (cp < 0.33)      auroraColor = mix(float3(0.1, 0.8, 0.3), float3(0.2, 1.0, 0.5), cp / 0.33);
    else if (cp < 0.66) auroraColor = mix(float3(0.2, 1.0, 0.5), float3(0.4, 0.3, 0.9), (cp - 0.33) / 0.33);
    else                auroraColor = mix(float3(0.4, 0.3, 0.9), float3(0.1, 0.8, 0.3), (cp - 0.66) / 0.34);

    scene.rgb += auroraColor * curtain * verticalFade * intensity;
    return scene;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float zoom = params[0];
    int maxIter = int(params[1]);
    float colorSpeed = params[2];

    float4 scene = sceneTexture.sample(smp, in.texCoord);

    // Julia set with time-varying c parameter
    float2 c = float2(sin(uniforms.time * 0.3 * colorSpeed) * 0.4 - 0.2,
                      cos(uniforms.time * 0.37 * colorSpeed) * 0.3);
    float2 z = (in.texCoord - 0.5) * zoom;
    // Correct for aspect ratio
    z.x *= uniforms.resolution.x / uniforms.resolution.y;

    int iter = 0;
    for (int i = 0; i < maxIter; i++) {
        if (dot(z, z) > 4.0) break;
        z = float2(z.x * z.x - z.y * z.y, 2.0 * z.x * z.y) + c;
        iter = i;
    }

    if (dot(z, z) <= 4.0) return scene; // Inside set — show scene

    // Map iteration count to color
    float t = float(iter) / float(maxIter);
    float3 fractalColor = float3(
        sin(t * 6.28318 * 3.0 + 0.0) * 0.5 + 0.5,
        sin(t * 6.28318 * 3.0 + 2.094) * 0.5 + 0.5,
        sin(t * 6.28318 * 3.0 + 4.189) * 0.5 + 0.5
    );

    // Blend fractal with scene
    float fractalAlpha = 0.6 * (1.0 - t);
    scene.rgb = mix(scene.rgb, fractalColor, fractalAlpha);
    return scene;
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float strength = params[0];
    float speed = params[1];
    float swirlRadius = params[2];

    float2 center = float2(0.5, 0.5);
    float2 delta = in.texCoord - center;
    float dist = length(delta);
    float angle = atan2(delta.y, delta.x);

    // Rotation falls off with distance
    float swirl = strength * smoothstep(swirlRadius, 0.0, dist) * sin(uniforms.time * speed);

    // Sample each channel at a different swirl amount
    float2 uvR = center + dist * float2(cos(angle + swirl * 1.1), sin(angle + swirl * 1.1));
    float2 uvG = center + dist * float2(cos(angle + swirl), sin(angle + swirl));
    float2 uvB = center + dist * float2(cos(angle + swirl * 0.9), sin(angle + swirl * 0.9));

    float r = sceneTexture.sample(smp, uvR).r;
    float g = sceneTexture.sample(smp, uvG).g;
    float b = sceneTexture.sample(smp, uvB).b;
    return float4(r, g, b, sceneTexture.sample(smp, in.texCoord).a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float speed = params[0];
    float satBoost = params[1];

    float4 color = sceneTexture.sample(smp, in.texCoord);

    // RGB → HSV
    float cMax = max(max(color.r, color.g), color.b);
    float cMin = min(min(color.r, color.g), color.b);
    float delta = cMax - cMin;

    float h = 0.0;
    if (delta > 0.001) {
        if (cMax == color.r)      h = fmod((color.g - color.b) / delta, 6.0);
        else if (cMax == color.g) h = (color.b - color.r) / delta + 2.0;
        else                      h = (color.r - color.g) / delta + 4.0;
        h /= 6.0;
        if (h < 0.0) h += 1.0;
    }
    float s = (cMax > 0.001) ? delta / cMax : 0.0;
    float v = cMax;

    // Rotate hue, boost saturation
    h = fract(h + uniforms.time * speed * 0.1);
    s = saturate(s * satBoost);

    // HSV → RGB
    float hh = h * 6.0;
    int hi = int(hh);
    float f = hh - float(hi);
    float p = v * (1.0 - s);
    float q = v * (1.0 - f * s);
    float t = v * (1.0 - (1.0 - f) * s);

    float3 rgb;
    if      (hi == 0) rgb = float3(v, t, p);
    else if (hi == 1) rgb = float3(q, v, p);
    else if (hi == 2) rgb = float3(p, v, t);
    else if (hi == 3) rgb = float3(p, q, v);
    else if (hi == 4) rgb = float3(t, p, v);
    else              rgb = float3(v, p, q);

    return float4(rgb, color.a);
}"

"fragment float4 fragment_postprocess(PostProcessVertexOut in [[stage_in]],
                                      texture2d<float> sceneTexture [[texture(0)]],
                                      sampler smp [[sampler(0)]],
                                      constant PostProcessUniforms& uniforms [[buffer(0)]],
                                      constant float* params [[buffer(1)]]) {
    float strength = params[0];
    float angle = params[1] * 3.14159 / 180.0;

    float2 texelSize = 1.0 / uniforms.resolution;
    float2 dir = float2(cos(angle), sin(angle)) * texelSize;

    float4 s1 = sceneTexture.sample(smp, in.texCoord - dir);
    float4 s2 = sceneTexture.sample(smp, in.texCoord + dir);

    float3 diff = (s2.rgb - s1.rgb) * strength;
    return float4(diff + 0.5, s1.a);
}"
